+    #[test]
+    fn status_clone_preserves_variant() {
+        let variants = [
+            LocalProcessStatus::Idle,
+            LocalProcessStatus::Run,
+            LocalProcessStatus::Sleep,
+            LocalProcessStatus::Stop,
+            LocalProcessStatus::Zombie,
+            LocalProcessStatus::Tracing,
